joi_block.script:
hold_ticks := 0
if ((#TemperatureSensor #Pantry).temperatureSensor_temperature >= 25) {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 1) {
(#AirConditioner #Switch #Pantry).switch_on()
        break
}
}
else {
hold_ticks = 0
}

